import{_ as a,c as i,o as l,a8 as o}from"./chunks/framework.BrmF0WDH.js";const h=JSON.parse('{"title":"04-Sandbox画布与交互","description":"","frontmatter":{},"headers":[],"relativePath":"onboarding/04-Sandbox画布与交互/index.md","filePath":"onboarding/04-Sandbox画布与交互/index.md","lastUpdated":1777649372000}'),d={name:"onboarding/04-Sandbox画布与交互/index.md"};function r(n,e,t,c,u,p){return l(),i("div",null,e[0]||(e[0]=[o('<h1 id="_04-sandbox画布与交互" tabindex="1">04-Sandbox画布与交互 <a class="header-anchor" href="#_04-sandbox画布与交互" aria-label="Permalink to &quot;04-Sandbox画布与交互&quot;">​</a></h1><h2 id="sandbox-的真实职责" tabindex="1">Sandbox 的真实职责 <a class="header-anchor" href="#sandbox-的真实职责" aria-label="Permalink to &quot;Sandbox 的真实职责&quot;">​</a></h2><p>很多人第一次看这个仓库，会把 <code>sandbox</code> 当成 runtime。实际上它不是。</p><p><code>packages/sandbox</code> 的职责是：</p><ul><li>挂载 iframe</li><li>建立编辑器和 runtime 的通信桥</li><li>维护选中框、蒙层、辅助线、高亮</li><li>承接拖拽、缩放、多选、吸附等交互</li></ul><p>它是“编辑态交互层”，不是业务页面执行层。</p><h2 id="boxcore-是对外总控" tabindex="1"><code>BoxCore</code> 是对外总控 <a class="header-anchor" href="#boxcore-是对外总控" aria-label="Permalink to &quot;`BoxCore` 是对外总控&quot;">​</a></h2><p><code>BoxCore</code> 统一管理三个子模块：</p><ul><li><code>BoxRender</code><ul><li>iframe 渲染和 runtime 桥接</li></ul></li><li><code>BoxMask</code><ul><li>蒙层、遮罩、选中框、参考线</li></ul></li><li><code>ActionManager</code><ul><li>鼠标键盘交互、拖拽缩放、多选、高亮</li></ul></li></ul><p>所以理解 sandbox，最好的办法不是从 UI 看，而是从这三个模块的职责边界看。</p><h2 id="iframe-为什么是必须的" tabindex="1">iframe 为什么是必须的 <a class="header-anchor" href="#iframe-为什么是必须的" aria-label="Permalink to &quot;iframe 为什么是必须的&quot;">​</a></h2><p>项目用 iframe 不是为了炫技，而是为了做隔离。</p><p>它至少解决了 4 个问题：</p><ol><li>编辑器样式不会污染业务页面</li><li>业务组件事件不会直接打到编辑器壳层</li><li>不同 runtime 可以独立演进</li><li>选中、高亮、拖拽可以在蒙层上做，不必入侵业务组件内部</li></ol><p>这也是该项目能够同时支持 Vue2 / Vue3 runtime 的基础之一。</p><h2 id="编辑器和-runtime-怎么握手" tabindex="1">编辑器和 runtime 怎么握手 <a class="header-anchor" href="#编辑器和-runtime-怎么握手" aria-label="Permalink to &quot;编辑器和 runtime 怎么握手&quot;">​</a></h2><p>握手流程在 <code>BoxRender</code> 和 runtime playground App 里最清楚：</p><ol><li><code>BoxRender.mount</code> 创建 iframe</li><li>给 iframe 的 <code>window</code> 注入 <code>window.quantum</code></li><li>runtime 启动后调用 <code>window.quantum.onRuntimeReady(...)</code></li><li>runtime 把自己的能力暴露出来</li></ol><p>暴露的核心接口包括：</p><ul><li><code>getApp</code></li><li><code>updateRootConfig</code></li><li><code>updatePageField</code></li><li><code>select</code></li><li><code>add</code></li><li><code>update</code></li><li><code>delete</code></li></ul><p>这套接口非常关键，它定义了“编辑态如何驱动运行态”。</p><h2 id="为什么还要有-boxmask" tabindex="1">为什么还要有 <code>BoxMask</code> <a class="header-anchor" href="#为什么还要有-boxmask" aria-label="Permalink to &quot;为什么还要有 `BoxMask`&quot;">​</a></h2><p>因为编辑器需要处理的是“编辑交互”，而不是“真实点击组件”。</p><p>例如：</p><ul><li>选中一个按钮时，你不希望触发按钮业务点击逻辑</li><li>拖拽一个元素时，你要拖的是它的编辑框，不是组件自己的鼠标事件</li><li>多选、辅助线、容器高亮这些能力，业务组件本身并不具备</li></ul><p>所以项目在 iframe 上方放了一层 mask，把编辑交互拦截出来单独处理。</p><h2 id="actionmanager-为什么复杂" tabindex="1"><code>ActionManager</code> 为什么复杂 <a class="header-anchor" href="#actionmanager-为什么复杂" aria-label="Permalink to &quot;`ActionManager` 为什么复杂&quot;">​</a></h2><p>因为它要解决的是低代码编辑器里最麻烦的一类问题：编辑坐标系和业务 DOM 坐标系的同步。</p><p>它要同时处理：</p><ul><li>单选</li><li>多选</li><li>高亮</li><li>拖拽</li><li>缩放</li><li>旋转</li><li>键盘辅助</li><li>容器悬停高亮</li></ul><p>这类逻辑天然比普通页面交互复杂。</p><h2 id="坐标换算是这一层的核心难点" tabindex="1">坐标换算是这一层的核心难点 <a class="header-anchor" href="#坐标换算是这一层的核心难点" aria-label="Permalink to &quot;坐标换算是这一层的核心难点&quot;">​</a></h2><p>项目存储的是设计稿坐标，但用户操作的是当前画布像素。</p><p>所以拖入新组件时会发生一系列换算：</p><ol><li>取鼠标在 sandbox 里的可视坐标</li><li>加上滚动偏移</li><li>根据设计稿宽度换算成 Schema 存储值</li><li>再根据父容器布局修正相对位置</li></ol><p>这就是 <code>packages/editor/src/components/layouts/sandbox/index.vue</code> 中那段坐标计算代码存在的根本原因。</p><h2 id="为什么选中态有两份" tabindex="1">为什么选中态有两份 <a class="header-anchor" href="#为什么选中态有两份" aria-label="Permalink to &quot;为什么选中态有两份&quot;">​</a></h2><p>你会看到选中相关状态分散在两边：</p><ul><li><code>EditorService</code><ul><li>关心“当前业务上选中了哪个节点”</li></ul></li><li><code>Sandbox / ActionManager</code><ul><li>关心“当前 DOM 层选中了哪个元素”</li></ul></li></ul><p>这不是重复，而是两个不同层次：</p><ul><li>一个是数据层选中</li><li>一个是交互层选中</li></ul><p>两者需要同步，但不能混为一谈。</p><h2 id="sandbox-这层的典型问题怎么查" tabindex="1">Sandbox 这层的典型问题怎么查 <a class="header-anchor" href="#sandbox-这层的典型问题怎么查" aria-label="Permalink to &quot;Sandbox 这层的典型问题怎么查&quot;">​</a></h2><h3 id="现象-1-节点明明存在-但选不中" tabindex="1">现象 1：节点明明存在，但选不中 <a class="header-anchor" href="#现象-1-节点明明存在-但选不中" aria-label="Permalink to &quot;现象 1：节点明明存在，但选不中&quot;">​</a></h3><p>优先检查：</p><ul><li>DOM 是否有对应 <code>id</code></li><li><code>getTargetElement</code> 是否能查到元素</li><li>mask 是否已挂载</li><li>是否被别的元素挡住</li></ul><h3 id="现象-2-拖拽后位置不对" tabindex="1">现象 2：拖拽后位置不对 <a class="header-anchor" href="#现象-2-拖拽后位置不对" aria-label="Permalink to &quot;现象 2：拖拽后位置不对&quot;">​</a></h3><p>优先检查：</p><ul><li>当前父布局是 <code>relative / absolute / fixed</code> 哪种</li><li><code>designWidth</code> 是否一致</li><li>当前 zoom 是否参与了换算</li></ul><h3 id="现象-3-iframe-里页面显示对了-但编辑器框选错位" tabindex="1">现象 3：iframe 里页面显示对了，但编辑器框选错位 <a class="header-anchor" href="#现象-3-iframe-里页面显示对了-但编辑器框选错位" aria-label="Permalink to &quot;现象 3：iframe 里页面显示对了，但编辑器框选错位&quot;">​</a></h3><p>优先检查：</p><ul><li><code>onPageElUpdate</code> 是否正确触发</li><li>page 元素尺寸是否已同步给 mask</li><li>zoom 和 scrollTop/scrollLeft 是否同时参与了计算</li></ul><h2 id="对新人最重要的结论" tabindex="1">对新人最重要的结论 <a class="header-anchor" href="#对新人最重要的结论" aria-label="Permalink to &quot;对新人最重要的结论&quot;">​</a></h2><p>遇到画布问题时，不要直接去怀疑 Vue 渲染，先判断它属于下面哪一类：</p><ol><li>Schema 不对</li><li>runtime 没同步</li><li>iframe DOM 对了，但 mask/Moveable 没对齐</li></ol><p>第三类问题才是 sandbox 自己的问题。</p>',56)]))}const m=a(d,[["render",r]]);export{h as __pageData,m as default};
